window.I18N={"404":{"h1":"Seite Nicht Gefunden","message":"Suchen Sie einen Rechner?","go_home":"Zur Startseite"},"site":{"title":"TurfCalculator","description":"Kostenlose Rasen- und Rollrasen-Rechner für Hausbesitzer","tagline":"Kostenlose Rechner — keine Anmeldung, kein Aufwand"},"nav":{"home":"Startseite","sod_calculator":"Rollrasen-Rechner","lawn_area_calculator":"Flächenrechner","grass_type_guide":"Rasensorten","grass_seed_calculator":"Saatgut-Rechner","fertilizer_calculator":"Dünger-Rechner","lawn_water_calculator":"Bewässerungsrechner","soil_calculator":"Erde-Rechner","area_converter":"Flächenumrechner","lawn_care_calendar":"Pflegekalender","about":"Über uns","privacy":"Datenschutz","terms":"Nutzungsbedingungen","disclaimer":"Haftungsausschluss","cookies":"Cookie-Richtlinie","language":"Sprache"},"pages":{"sod-calculator":"rollrasen-rechner","lawn-area-calculator":"rasenflaechenrechner","grass-type-guide":"rasensorten-guide","grass-seed-calculator":"saatgut-rechner","fertilizer-calculator":"duenger-rechner","lawn-water-calculator":"bewaesserungsrechner","soil-calculator":"erde-rechner","area-converter":"flaechenumrechner","lawn-care-calendar":"rasenpflegekalender","about":"ueber-uns","privacy-policy":"datenschutz","terms":"nutzungsbedingungen","disclaimer":"haftungsausschluss","cookie-policy":"cookie-richtlinie"},"common":{"calculate":"Berechnen","reset":"Zurücksetzen","result":"Ergebnis","results":"Ergebnisse","area":"Fläche","length":"Länge","width":"Breite","diameter":"Durchmesser","depth":"Tiefe","unit_ft":"Fuß","unit_m":"m","unit_in":"Zoll","unit_cm":"cm","unit_sqft":"ft²","unit_sqm":"m²","unit_sqyd":"yd²","unit_ac":"Acres","unit_ha":"Hektar","grass_type":"Rasensorte","includes_extra":"Enthält {percent}% Zuschlag für Schnitte und Anpassungen","based_on_area":"Basierend auf einer Rasenfläche von {area} {unit}","need_different":"Brauchen Sie eine andere Form oder Rollengröße?","add_another_area":"+ Weitere Fläche hinzufügen","subtract_area":"− Fläche abziehen (Pool, Haus, Einfahrt)","total":"Gesamt","send_to_sod":"→ Berechnen, wie viel Rollrasen ich brauche","or":"oder","est_cost":"Geschätzte Kosten","tip":"Tipp","faq_title":"Häufig Gestellte Fragen","related_tools":"Verwandte Werkzeuge","share":"Teilen","print":"Drucken","copy":"Kopieren","copied":"Kopiert!","close":"Schließen","more_options":"Weitere Optionen","warm_season":"Warmes Saison","cool_season":"Kühle Saison","full_sun":"Volle Sonne","partial_sun":"Halbschatten","shade":"Schatten","new_lawn":"Neuer Rasen","overseeding":"Nachsaat","regular":"Regulär","starter":"Starter","winter_prep":"Winter-Vorbereitung","unit_acres":"Acre","skip_to_content":"Zum Inhalt springen","lbs":"Pfund","gallons":"Gallonen","minutes":"Minuten","cu_yd":"m³","cu_ft":"ft³","cu_m":"m³","unit_l":"L"},"cookie_banner":{"message":"Wir verwenden essenzielle Cookies, damit unsere Rechner funktionieren, und optionale Analyse-Cookies, um die Seite zu verbessern.","essential_only":"Nur Essenzielle","accept_all":"Alle Akzeptieren","customize":"Anpassen"},"footer":{"copyright":"© 2026 TurfCalculator. Kostenlose Rasenrechner für alle.","disclaimer_short":"Berechnungen sind Schätzungen. Bitte bei Ihrem lokalen Anbieter überprüfen.","privacy":"Datenschutz","terms":"Nutzungsbedingungen","disclaimer":"Haftungsausschluss","cookies":"Cookies"},"home":{"h1":"Kostenlose Rollrasen- & Rasenrechner","meta_title":"TurfCalculator — Kostenlose Rasen- & Rollrasenrechner","meta_description":"Kostenlose Rechner für Rollrasen, Saatgut, Dünger, Erde und Bewässerung Ihres Rasens. Genaue Ergebnisse in 30 Sekunden. Keine Anmeldung erforderlich.","hero_title":"Wie viel Rollrasen brauchen Sie?","hero_subtitle":"Geben Sie Ihre Rasenabmessungen ein und erhalten Sie sofort eine Antwort","full_sod_calculator":"→ Vollständiger Rollrasen-Rechner","more_calculators":"Weitere Rechner","popular_questions":"Beliebte Fragen","question_1":"Wie viele Quadratmeter hat eine Palette Rollrasen?","question_2":"Wie viel kostet eine Rolle Rollrasen?","question_3":"Beste Rasensorte für volle Sonne?","trust_banner":"✅ Kostenlos · 🔒 Keine Anmeldung · 📊 Branchenübliche Formeln","popular_question_1":"Wie viele Quadratfuß auf einer Rollrasenpalette?","popular_question_2":"Was kostet eine Rolle Rollrasen?","popular_question_3":"Bester Rasentyp für volle Sonne?","popular_question_4":"Wie berechne ich, wie viel Rollrasen ich brauche?","popular_answer_1":"Eine Standardpalette deckt 500 Quadratfuß ab (ca. 450 Rollen).","popular_answer_2":"Rollrasen kostet $0,30–$0,80 pro Quadratfuß installiert, oder $0,15–$0,40 pro Quadratfuß für Material.","popular_answer_3":"Bermudagras, Zoysia und Bahiagrass gedeihen in voller Sonne mit 6+ Stunden direktem Sonnenlicht.","popular_answer_4":"Messen Sie Länge und Breite Ihres Rasens in Fuß, multiplizieren Sie sie für die Quadratfläche und teilen Sie durch die Rollengröße (typisch 10 Quadratfuß). Fügen Sie 10% für Verschnitt hinzu."},"sod_calculator":{"h1":"Rollrasen-Rechner","meta_title":"Rollrasen-Rechner — Wie Viel Brauche Ich?","meta_description":"Berechnen Sie genau, wie viele Rollen und Paletten Rollrasen Sie brauchen. Kostenloser Rechner mit Verschnittfaktor. Für jede Form. Keine Anmeldung.","length_label":"Länge","length_help":"Messen Sie die längste Seite Ihres Rasens","width_label":"Breite","width_help":"Messen Sie die kürzeste Seite Ihres Rasens","shape_label":"Rasenform","shape_rectangle":"Rechteck","shape_square":"Quadrat","shape_circle":"Kreis","shape_oval":"Oval / Ellipse","shape_triangle":"Dreieck","shape_trapezoid":"Trapez","side_label":"Seite","major_axis_label":"Hauptachse","minor_axis_label":"Nebenachse","base_label":"Basis","height_label":"Höhe","parallel_a_label":"Parallele Seite A","parallel_b_label":"Parallele Seite B","waste_factor_label":"Verschnittfaktor","waste_simple":"Einfach (5%)","waste_normal":"Normal (10%)","waste_complex":"Komplex (15%)","waste_very_complex":"Sehr Komplex (20%)","roll_size_label":"Rollrasen-Rollengröße","roll_standard":"Standard (61×152 cm = 1 m²)","roll_mini":"Mini (46×61 cm = 0,28 m²)","roll_large":"Groß (61×206 cm = 1,25 m²)","roll_custom":"Benutzerdefinierte Größe","custom_roll_width":"Rollenbreite","custom_roll_length":"Rollenlänge","results_title":"Ihre Ergebnisse","rolls_needed":"Benötigte Rollen","pallets_needed":"Benötigte Paletten","estimated_cost":"Geschätzte Kosten","cost_range":"{low} – {high}","total_area":"Gesamtfläche (mit Verschnitt)","tip_extra":"Kaufen Sie 1 Rolle extra für zukünftige Reparaturen","how_to_h2":"Wie Man Berechnet, Wie Viel Rollrasen Man Braucht","how_to_step1":"Messen Sie Länge und Breite Ihres Rasens in Metern.","how_to_step2":"Multiplizieren Sie Länge × Breite, um die Fläche in Quadratmetern zu erhalten.","how_to_step3":"Addieren Sie einen Verschnittfaktor (5–20%) für Schnitte, Anpassungen und unregelmäßige Kanten.","how_to_step4":"Teilen Sie die Gesamtfläche durch die Rollengröße.","how_to_step5":"Teilen Sie die Rollen durch die Anzahl pro Palette, um die Paletten zu schätzen.","roll_sizes_h2":"Rollrasen-Rollengrößen Erklärt","roll_sizes_table_header_size":"Rollengröße","roll_sizes_table_header_coverage":"Abdeckung","roll_sizes_table_header_use":"Am Besten Für","faq":[{"q":"Wie viele Quadratmeter hat eine Palette Rollrasen?","a":"Eine Standardpalette deckt 40–55 m² und enthält 40–55 Rollen à ca. 1 m². Kleine Paletten decken ca. 35 m², große bis zu 65 m². Erkundigen Sie sich bei Ihrem lokalen Anbieter nach den genauen Palettengrößen."},{"q":"Wie viel kostet eine Rolle Rollrasen?","a":"Rollrasen kostet typischerweise 2–8 € pro m². Die Preise variieren nach Rasensorte, Region und Menge. Bermudagras und Zoysia sind eher teurer, während Festuca oft günstiger ist."},{"q":"Sollte ich extra Rollrasen kaufen? Wie viel?","a":"Ja, planen Sie immer 5–15% extra für Verschnitt durch Schnitte an Kurven, Bäumen und Rändern ein. Verwenden Sie 5% für einfache Rechtecke, 10% für normale Formen und 15–20% für komplexe oder unregelmäßige Rasenflächen mit vielen Hindernissen."},{"q":"Was ist der Verschnittfaktor und warum brauche ich ihn?","a":"Der Verschnittfaktor berücksichtigt den Rollrasen, der beim Schneiden und Anpassen an Kurven, Wege, Bäume und Ränder verloren geht. Ohne ihn kann es passieren, dass Sie zu wenig bestellen und eine zweite Bestellung aufgeben müssen — die möglicherweise nicht zur ersten Lieferung in Farbe und Frische passt."},{"q":"Wie lange kann Rollrasen vor der Verlegung liegen?","a":"Rollrasen sollte bei kühlem Wetter innerhalb von 24 Stunden nach der Lieferung verlegt werden, bei heißem Wetter innerhalb von 12 Stunden. Rollrasen, der zu lange liegt, erhitzt sich, wird gelb und stirbt ab. Sorgen Sie dafür, dass der Boden vor der Ankunft des Rollrasens vorbereitet ist."}],"advanced_toggle":"Erweiterte Optionen","advanced_label":"Erweitert","shape_l_shape":"L-Form","radius_label":"Radius","l_length_label":"Hauptlänge","l_width_label":"Hauptbreite","l_extension_label":"Erweiterungslänge","l_ext_width_label":"Erweiterungsbreite"},"lawn_area_calculator":{"h1":"Rasenflächenrechner","meta_title":"Rasenflächenrechner — Gartenfläche Messen","meta_description":"Berechnen Sie Ihre Rasenfläche in Quadratmetern, Quadratfuß, Acres und mehr. Unterstützt Rechtecke, Kreise, Dreiecke und Mehrzonen-Gärten","shape_label":"Rasenform","shape_rectangle":"Rechteck","shape_square":"Quadrat","shape_circle":"Kreis","shape_oval":"Oval / Ellipse","shape_triangle":"Dreieck","shape_trapezoid":"Trapez","length_label":"Länge","width_label":"Breite","side_label":"Seite","diameter_label":"Durchmesser","major_axis_label":"Hauptachse","minor_axis_label":"Nebenachse","base_label":"Basis","height_label":"Höhe","parallel_a_label":"Parallele Seite A","parallel_b_label":"Parallele Seite B","zone_label":"Zone {number}","remove_zone":"Entfernen","your_lawn":"Ihr Rasen","total_area":"Gesamtfläche","conversions":"Umrechnungen","subtract_zone_label":"Abzugszone {number}","how_to_measure_h2":"Wie Man Seinen Garten Für Rollrasen Vermisst","how_to_measure_p1":"Für einen einfachen rechteckigen Rasen messen Sie Länge und Breite mit einem Maßband und multiplizieren diese.","how_to_measure_p2":"Für unregelmäßige Gärten teilen Sie die Fläche in einfache Formen (Rechtecke, Kreise, Dreiecke) auf, berechnen jede einzeln und addieren sie dann.","how_to_measure_p3":"Ziehen Sie Flächen ab, für die Sie keinen Rollrasen brauchen: Pools, Einfahrten, Hausgrundriss, Terrassen und Wege.","common_sizes_h2":"Übliche Rasengrößen Als Referenz","common_sizes_small":"Kleines Stadthaus: ~280–465 m²","common_sizes_quarter":"Vorstadt ¼ Acre: ~1.012 m²","common_sizes_half":"½ Acre: ~2.024 m²","common_sizes_acre":"1 Acre: ~4.047 m²","faq":[{"q":"Wie vermisse ich einen unregelmäßig geformten Rasen?","a":"Teilen Sie ihn in einfache Formen — Rechtecke, Kreise und Dreiecke. Vermessen Sie jeden Abschnitt einzeln, berechnen Sie die Fläche für jeden und addieren Sie alles. Verwenden Sie die Schaltfläche 'Weitere Fläche hinzufügen', um mehrere Zonen einzugeben."},{"q":"Sollte ich mein Haus und die Einfahrt von der Fläche abziehen?","a":"Ja. Messen Sie nur die Fläche, auf der Sie tatsächlich Rollrasen verlegen möchten. Verwenden Sie die Option 'Fläche abziehen', um den Hausgrundriss, die Einfahrt, die Terrasse, den Pool und alle anderen Nicht-Rasenflächen zu entfernen."},{"q":"Wie genau muss meine Messung sein?","a":"Innerhalb von 5–10% ist meist ausreichend. Kleine Messfehler werden durch den Verschnittfaktor (extra Rollrasen für Schnitte) abgedeckt. Bei sehr großen oder teuren Projekten sollten Sie eine professionelle Vermessung in Betracht ziehen."},{"q":"Kann ich Google Maps verwenden, um meinen Rasen zu vermessen?","a":"Ja, Google Maps und Satellitenbild-Tools können eine grobe Schätzung liefern. Luftbilder zeigen jedoch möglicherweise keine Hänge, Höhenunterschiede oder Landschaftsdetails, die die tatsächliche benötigte Rollrasenmenge beeinflussen."},{"q":"Was ist, wenn mein Rasen an einem Hang liegt?","a":"Hanglagen benötigen mehr Rollrasen als flache Messungen vermuten lassen, da die tatsächliche Oberfläche größer ist. Bei mäßigen Hängen 5–10% extra einplanen. Bei steilen Hängen 10–20% extra."}],"length_help":"Messen Sie die längste Seite Ihres Rasens","width_help":"Messen Sie die kürzeste Seite Ihres Rasens","send_to_sod":"→ Berechnen, wie viel Rasen ich brauche","add_area":"+ Weiteren Bereich hinzufügen","subtract_area":"− Bereich abziehen (Pool, Haus, Einfahrt)"},"grass_type_guide":{"h1":"Rasensorten Im Vergleich","meta_title":"Beste Rasensorten — Vergleichsleitfaden","meta_description":"Vergleichen Sie warme und kühle Rasensorten Seite an Seite. Finden Sie den besten Rasen für volle Sonne, Schatten, hohe Belastung und wenig Pflege","warm_cool_toggle":"Saisontyp","warm_season_tab":"Warmes Saison","cool_season_tab":"Kühle Saison","comparison_table_h2":"Detaillierte Vergleichstabelle","table_header_name":"Rasensorte","table_header_season":"Saison","table_header_sun":"Sonne","table_header_drought":"Trockentoleranz","table_header_traffic":"Belastungstoleranz","table_header_maintenance":"Pflege","table_header_establish":"Etablierung","maintenance_low":"Niedrig","maintenance_medium":"Mittel","maintenance_high":"Hoch","establish_slow":"Langsam","establish_moderate":"Mäßig","establish_fast":"Schnell","tolerance_1":"Sehr Niedrig","tolerance_2":"Niedrig","tolerance_3":"Mäßig","tolerance_4":"Hoch","tolerance_5":"Sehr Hoch","pros_label":"Vorteile","cons_label":"Nachteile","best_for_label":"Am Besten Für","usda_zones_label":"USDA-Zonen","grass_types":{"bermudagrass":{"name":"Bermudagras","description":"Robustes, schnell wucherndes Warmzeitrasengras, das in voller Sonne gedeiht und starke Belastung verträgt. Die erste Wahl für Sportplätze und aktive Familiengärten in südlichen Klimazonen.","pros":["Ausgezeichnete Hitze- und Trockentoleranz","Belastbar bei starkem Fußverkehr","Schnell wuchernd und selbstreparierend"],"cons":["Geht im Winter in Ruhephase (wird braun)","Benötigt volle Sonne — Probleme im Schatten"],"sun":"full_sun","tags":["warm_season","full_sun","high_traffic"],"drought":"Sehr hoch","maintenance":"Hoch"},"zoysia":{"name":"Zoysiagras","description":"Dichtes, teppichartiges Warmzeitrasengras mit guter Kältetoleranz. Langsamer bei der Etablierung, bildet aber einen dichten, unkrautresistenten Rasen, der das Warten wert ist.","pros":["Gute Kältetoleranz für ein Warmzeitrasengras","Dichtes Wachstum verdrängt Unkraut","Geringer Wasserbedarf einmal etabliert"],"cons":["Langsam bei der Etablierung — kann 2+ Saisons dauern","Bildet dichten Filz, der vertikutiert werden muss"],"sun":"partial_sun","tags":["warm_season","partial_sun","low_maintenance"],"drought":"Hoch","maintenance":"Mittel"},"centipede":{"name":"Centipedegras","description":"Pflegeleichtes Warmzeitrasengras, bekannt als 'Faulenzergras'. Bevorzugt saure Böden und braucht weniger Dünger als die meisten anderen Sorten.","pros":["Sehr geringer Pflege- und Düngebedarf","Toleriert saure Bodenverhältnisse","Mäßige Schattentoleranz"],"cons":["Langsam bei der Etablierung und Ausbreitung","Geringe Belastungstoleranz — nicht für aktive Gärten"],"sun":"partial_sun","tags":["warm_season","partial_sun","low_maintenance"],"drought":"Mittel","maintenance":"Niedrig"},"st_augustine":{"name":"St.-Augustin-Gras","description":"Grobtexturiertes Warmzeitrasengras mit der besten Schattentoleranz unter den südlichen Gräsern. Beliebt in Küstengebieten wegen der Salztoleranz.","pros":["Beste Schattentoleranz aller Warmzeitrasengräser","Salztolerant — ideal für Küstengebiete","Schnelle Etablierung aus Rollrasen oder Stecklingen"],"cons":["Grobe Textur entspricht möglicherweise nicht allen Vorlieben","Anfällig für Chinch-Wanzen und Krankheiten"],"sun":"shade","tags":["warm_season","shade","coastal"],"drought":"Mittel","maintenance":"Hoch"},"bahiagrass":{"name":"Bahiagras","description":"Robustes, trockenheitsresistentes Warmzeitrasengras für den tiefen Süden. Gedeiht auf sandigen, nährstoffarmen Böden, wo andere Gräser versagen. Offener Wuchs mit sichtbaren Samenständen.","pros":["Äußerst trockenheitstolerant — überlebt nur mit Regen","Gedeiht auf armen, sandigen Böden","Geringer Dünge- und Pflegebedarf"],"cons":["Offener, grober Wuchs — kein gepflegtes Aussehen","Bildet hohe Samenstände, die häufiges Mähen erfordern"],"sun":"full_sun","tags":["warm_season","full_sun","low_maintenance"],"drought":"Sehr hoch","maintenance":"Niedrig"},"kentucky_bluegrass":{"name":"Wiesenrispe","description":"Das klassische üppige, dunkelgrüne Rasengras des nördlichen US. Breitet sich durch unterirdische Rhizome aus und füllt kahle Stellen, dichtet einen dichten, schönen Rasen.","pros":["Reiche, dunkelgrüne Farbe — der klassische Rasenlook","Selbstreparierend durch unterirdische Rhizome","Ausgezeichnete Winterhärte"],"cons":["Hoher Pflegeaufwand — braucht regelmäßige Bewässerung und Düngung","Langsame Keimung aus Saatgut (2–4 Wochen)"],"sun":"full_sun","tags":["cool_season","full_sun","high_maintenance"],"drought":"Niedrig","maintenance":"Hoch"},"tall_fescue":{"name":"Rohrschwingel","description":"Anpassungsfähiges Kaltzeitrasengras mit tiefen Wurzeln für Trockenheitsresistenz. Eines der vielseitigsten Rasengräser mit guter Leistung in Sonne, Schatten und Übergangsklima.","pros":["Tiefes Wurzelsystem für ausgezeichnete Trockenheitsresistenz","Gute Schattentoleranz für ein Kaltzeitrasengras","Geringerer Pflegeaufwand als Wiesenrispe"],"cons":["Breitet sich nicht aus — kahle Stellen müssen nachgesät werden","Kann Horste bilden bei mangelnder Pflege"],"sun":"partial_sun","tags":["cool_season","partial_sun","low_maintenance"],"drought":"Hoch","maintenance":"Mittel"},"perennial_ryegrass":{"name":"Deutsches Weidelgras","description":"Schnell keimendes Kaltzeitrasengras mit feiner Textur. Oft in Saatgutmischungen für schnelle Etablierung und zur Nachsaat von Warmzeitrasen für winterliches Grün verwendet.","pros":["Keimt in nur 5–7 Tagen — am schnellsten aller Gräser","Feine Textur und sattgrüne Farbe","Ausgezeichnete Verschleißtoleranz für aktive Rasen"],"cons":["Weniger winterhart als andere Kaltzeitrasengräser","Kurzlebig als alleiniger Rasen — am besten in Mischungen"],"sun":"full_sun","tags":["cool_season","full_sun","quick_establish"],"drought":"Niedrig","maintenance":"Mittel"},"fine_fescue":{"name":"Rotschwingel","description":"Feinblättriges Kaltzeitrasengras, das in Schatten und bei wenig Pflege glänzt. Das schattentoleranteste aller gängigen Rasengräser.","pros":["Beste Schattentoleranz aller Rasengräser","Sehr pflegeleicht — braucht wenig Wasser oder Dünger","Feine, attraktive Blatttextur"],"cons":["Geringe Belastungstoleranz — leicht beschädigt","Probleme in heißen, feuchten Sommern"],"sun":"shade","tags":["cool_season","shade","low_maintenance"],"drought":"Mittel","maintenance":"Niedrig"},"sun_shade_mix":{"name":"Sonnen-/Schatten-Mischung","description":"Eine Mischung aus Kentucky Bluegrass und Feinschwingel, die sich an sonnige und schattige Bereiche anpasst.","pros":["Passt sich wechselndem Licht an","Gut für gemischte Gärten","Mittlerer Pflegeaufwand"],"drought":"Mittel","maintenance":"Mittel","sun":"Sonne bis Halbschatten"}},"faq":[{"q":"Was ist der Unterschied zwischen Warmzeit- und Kaltzeitrasengräsern?","a":"Warmzeitrasengräser (Bermudagras, Zoysia, St.-Augustin-Gras) gedeihen in südlichen Klimazonen mit heißen Sommern und milden Wintern. Sie gehen im Winter in Ruhephase und werden braun. Kaltzeitrasengräser (Wiesenrispe, Schwingel, Weidelgras) wachsen am besten in nördlichen Klimazonen mit kalten Wintern und gemäßigten Sommern. Sie bleiben in ihren bevorzugten Zonen ganzjährig grün."},{"q":"Welche Rasensorte ist am besten für volle Sonne?","a":"Für warme Klimata ist Bermudagras die beste Wahl für volle Sonne. Für kühle Klimata sind Wiesenrispe und Deutsches Weidelgras am besten in voller Sonne. Rohrschwingel ist eine gute Allround-Wahl für gemischte Bedingungen."},{"q":"Welches Gras wächst am besten im Schatten?","a":"Rotschwingel ist das schattentoleranteste Kaltzeitrasengras. Für warme Klimata ist St.-Augustin-Gras die beste Schattenoption. Kein Gras gedeiht im tiefen Schatten — wenn eine Fläche weniger als 3 Stunden direktes Sonnenlicht bekommt, sollten Sie Bodendecker oder Mulch in Betracht ziehen."},{"q":"Kann ich Warm- und Kaltzeitrasengräser mischen?","a":"Das wird generell nicht empfohlen. Sie haben unterschiedliche Wachstumsperioden, Bewässerungsbedürfnisse und Schnitthöhen. Die Ausnahme ist die Nachsaat: Sie können einen Warmzeitrasen mit Deutschem Weidelgras nachsäen für winterliche grüne Farbe."},{"q":"Welches Gras ist am besten für stark beanspruchte Flächen?","a":"Bermudagras ist das widerstandsfähigste Warmzeitrasengras für starke Belastung. Für Kaltzeitrasen vertragen Deutsches Weidelgras und Wiesenrispe Belastung gut. Rohrschwingel ist aufgrund seines tiefen Wurzelsystems ebenfalls eine gute Wahl."}],"season_toggle_label":"Rasen-Saisontyp","cards_label":"Rasentypen"},"grass_seed_calculator":{"h1":"Saatgut-Rechner","meta_title":"Rasensaatgut-Rechner — Wie Viel Saatgut Brauche Ich? (2026)","meta_description":"Berechnen Sie, wie viel Rasensaatgut Sie für Ihren Rasen brauchen. Kostenloser Rechner mit Saatmengen für alle Rasensorten. Neuer Rasen oder Nachsaat","area_label":"Rasenfläche","area_help":"Geben Sie Ihre Rasenfläche in Quadratmetern ein","grass_type_label":"Rasensorte","project_type_label":"Projekttyp","project_new_lawn":"Neuer Rasen","project_overseeding":"Nachsaat","results_seed_needed":"Benötigtes Saatgut","results_bags":"Benötigte Säcke","results_rate":"Ausbringungsmenge","results_rate_value":"{rate} kg pro 100 m²","seed_rate_note":"Die angezeigte Menge gilt für {project_type}. Bei Nachsaat wird etwa die Hälfte der Saatmenge eines neuen Rasens verwendet.","tip_timing":"Beste Saatzeit: Frühherbst für Kaltzeitrasengräser, Spätfrühling für Warmzeitrasengräser.","how_to_h2":"Wie Man Rasensaatgutmengen Berechnet","how_to_step1":"Messen Sie Ihre Rasenfläche in Quadratmetern.","how_to_step2":"Wählen Sie Ihre Rasensorte — jede hat eine andere empfohlene Saatmenge.","how_to_step3":"Wählen Sie neuer Rasen oder Nachsaat — Nachsaat benötigt etwa die halbe Saatmenge.","how_to_step4":"Der Rechner wendet die Menge pro 100 m² auf Ihre Gesamtfläche an.","faq":[{"q":"Wie viel Rasensaatgut brauche ich pro Quadratmeter?","a":"Das hängt von der Rasensorte ab. Wiesenrispe braucht etwa 1–1,5 kg pro 100 m² (neuer Rasen), während Rohrschwingel 3–4 kg pro 100 m² benötigt. Nachsaatmengen sind etwa die Hälfte der Mengen für neue Rasen."},{"q":"Kann ich zu viel Rasensaatgut ausbringen?","a":"Ja. Zu viel Saatgut führt zu Konkurrenz um Wasser, Nährstoffe und Licht, was schwaches, spärliches Gras erzeugt, das anfällig für Krankheiten ist. Halten Sie sich an die empfohlenen Mengen für Ihre Rasensorte."},{"q":"Sollte ich säen oder Rollrasen verlegen?","a":"Rollrasen gibt Ihnen einen sofortigen Rasen, kostet aber 10–20 mal mehr als Saatgut. Saatgut braucht 4–8 Wochen zur Etablierung, ist aber viel erschwinglicher. Saatgut ist besser für große Flächen und geduldige Hausbesitzer; Rollrasen ist besser für schnelle Ergebnisse und erosionsgefährdete Hänge."},{"q":"Wann ist die beste Zeit, Rasensaatgut zu säen?","a":"Kaltzeitrasengräser: Frühherbst (September–Oktober), wenn der Boden warm und die Luft kühl ist. Warmzeitrasengräser: Spätfrühling (Mai–Juni), wenn die Bodentemperaturen 18–21°C erreichen. Vermeiden Sie die Aussaat in der Sommerhitze."},{"q":"Wie lange dauert es, bis Rasensaatgut keimt?","a":"Deutsches Weidelgras: 5–7 Tage. Rohrschwingel: 7–12 Tage. Wiesenrispe: 14–28 Tage. Rotschwingel: 7–14 Tage. Warmzeitrasengräser: 14–30 Tage. Halten Sie den Boden während der Keimung gleichmäßig feucht."}],"st_augustine":"St. Augustine-Gras","sod_only_msg":"Wird in der Regel als Rollrasen gepflanzt — Saatgut ist kaum erhältlich.","lb_bags":"Pfund-Säcke"},"fertilizer_calculator":{"h1":"Dünger-Rechner","meta_title":"Rasendünger-Rechner — Wie Viel Dünger Soll Ich Ausbringen?","meta_description":"Berechnen Sie, wie viel Rasendünger Sie ausbringen sollen. Kostenloser Rechner für regulären, Starter- und Winterdünger. Keine Anmeldung.","area_label":"Rasenfläche","area_help":"Geben Sie Ihre Rasenfläche in Quadratmetern ein","fertilizer_type_label":"Düngerart","type_regular":"Regulär","type_starter":"Starter","type_winter":"Winter-Vorbereitung","type_regular_desc":"Für etablierte Rasen während der Wachstumsperiode","type_starter_desc":"Für neue Saat oder Rollrasen — mehr Phosphor für Wurzelwachstum","type_winter_desc":"Herbstanwendung zur Vorbereitung des Grases auf die Winterruhe","results_fertilizer_needed":"Benötigter Dünger","results_bags":"Benötigte Säcke","results_application_rate":"Ausbringungsmenge","results_rate_value":"{rate} kg pro 100 m²","results_when_to_apply":"Wann Ausbringen","when_regular":"Im Frühjahr und Herbst während des aktiven Wachstums ausbringen.","when_starter":"Zum Zeitpunkt der Aussaat oder Rollrasenverlegung ausbringen.","when_winter":"Im Spätherbst ausbringen, nachdem das Wachstum stoppt, aber bevor der Boden gefriert.","tip_watering":"Bewässern Sie Ihren Rasen innerhalb von 24 Stunden nach dem Düngen, um die Nährstoffe zu aktivieren und Verbrennungen zu vermeiden.","how_to_h2":"Wie Man Düngermengen Berechnet","how_to_step1":"Messen Sie Ihre Rasenfläche in Quadratmetern.","how_to_step2":"Wählen Sie die Düngerart nach den aktuellen Bedürfnissen Ihres Rasens.","how_to_step3":"Der Rechner wendet die empfohlene Stickstoffmenge pro 100 m² an.","how_to_step4":"Die Ergebnisse zeigen die benötigte Gesamtmenge in kg und die Anzahl der zu kaufenden Säcke.","faq":[{"q":"Wie viel Dünger soll ich auf meinen Rasen ausbringen?","a":"Als Faustregel gilt 0,5 kg tatsächlicher Stickstoff pro 100 m² pro Anwendung. Die meisten Hausbesitzer düngen 2–4 mal pro Jahr. Dieser Rechner verwendet Standard-NPK-Verhältnisse, um die benötigte Gesamtproduktmenge zu bestimmen."},{"q":"Was ist Starterdünger?","a":"Starterdünger hat einen höheren Phosphorgehalt (die mittlere Zahl im NPK-Verhältnis), um die Wurzelentwicklung bei neuem Gras zu fördern. Verwenden Sie ihn bei der Aussaat eines neuen Rasens oder der Verlegung von Rollrasen. Wechseln Sie zu regulärem Dünger, sobald der Rasen etabliert ist."},{"q":"Wann sollte ich Winterdünger ausbringen?","a":"Bringen Sie Winterdünger im Spätherbst aus, typischerweise Oktober–November, nachdem das Gras aufgehört hat zu wachsen, aber bevor der Boden gefriert. Dies hilft den Wurzeln, Energie für das Überleben im Winter und das Ergrünen im Frühling zu speichern."},{"q":"Kann ich meinen Rasen überdüngen?","a":"Ja. Überdüngung kann Ihr Gras verbrennen, übermäßiges oberirdisches Wachstum auf Kosten der Wurzeln verursachen und Gewässer belasten. Halten Sie sich immer an die empfohlenen Mengen und bringen Sie nie mehr aus, als auf dem Etikett angegeben ist."},{"q":"Sollte ich vor oder nach dem Regen düngen?","a":"Bringen Sie Dünger auf trockenem Gras aus und bewässern Sie ihn innerhalb von 24 Stunden ein. Nicht vor starkem Regen ausbringen — der Dünger kann abgewaschen werden, bevor er aufgenommen wird. Leichter Regen nach der Anwendung ist in Ordnung und kann beim Einwaschen helfen."}],"timing_starter":"Bei Neuanlage oder Nachsaat auftragen. Am besten im frühen Frühling oder Herbst.","timing_winter":"Im Spätherbst (Oktober–November) vor dem ersten Frost auftragen, um die Wurzeln auf den Winter vorzubereiten.","timing_maintenance":"Während der aktiven Wachstumsperiode auftragen. Kühle Jahreszeit: Frühling & Herbst. Warme Jahreszeit: Später Frühling bis Sommer."},"lawn_water_calculator":{"h1":"Bewässerungsrechner","meta_title":"Bewässerungsrechner — Wie Viel Wasser?","meta_description":"Berechnen Sie, wie viel Wasser Ihr Rasen pro Woche braucht. Kostenloser Bewässerungsrechner basierend auf Rasensorte und Fläche. Keine Anmeldung.","area_label":"Rasenfläche","area_help":"Geben Sie Ihre Rasenfläche in Quadratmetern ein","grass_type_label":"Rasensorte","results_weekly_water":"Wöchentlicher Wasserbedarf","results_minutes_per_session":"Minuten Pro Bewässerung","results_sessions_per_week":"Bewässerungen Pro Woche","results_gallons_per_week":"Liter Pro Woche","weekly_water_value":"{gallons} Liter","sessions_value":"{count} mal pro Woche","minutes_value":"{minutes} Minuten pro Bewässerung","tip_watering_depth":"Bewässern Sie tief und selten. Ziel: den Boden bei jeder Bewässerung bis zu einer Tiefe von 15 cm durchfeuchten.","tip_early_morning":"Bewässern Sie am frühen Morgen (5–9 Uhr), um Verdunstung und Krankheitsrisiko zu reduzieren.","how_to_h2":"Wie Viel Wasser Braucht Ihr Rasen?","how_to_step1":"Die meisten Rasen brauchen 25–38 mm Wasser pro Woche, einschließlich Niederschlag.","how_to_step2":"Teilen Sie das wöchentliche Wasser in 2–3 Bewässerungen für tiefes Wurzelwachstum auf.","how_to_step3":"Jede Bewässerung sollte etwa 12 mm Wasser liefern.","how_to_step4":"Verwenden Sie eine Regenmessgerät oder eine leere Thunfischdose, um die Sprinklerleistung zu messen.","faq":[{"q":"Wie viele Minuten soll ich meinen Rasen bewässern?","a":"Die meisten Sprinkler liefern etwa 12 mm pro 30 Minuten. Für einen typischen Rasen, der 25 mm pro Woche braucht, bewässern Sie 30 Minuten pro Durchgang, 2–3 mal pro Woche. Die tatsächliche Zeit variiert je nach Sprinklertyp und Wasserdruck — messen Sie mit einem Regenmessgerät."},{"q":"Ist es besser, jeden Tag oder alle paar Tage zu bewässern?","a":"Bewässern Sie tief 2–3 mal pro Woche statt leicht jeden Tag. Tiefes, seltenes Gießen fördert tiefes Wurzelwachstum und macht Ihren Rasen trockenheitsresistenter. Tägliches flaches Gießen fördert schwache, flache Wurzeln."},{"q":"Zu welcher Tageszeit soll ich meinen Rasen bewässern?","a":"Früher Morgen (5–9 Uhr) ist ideal. Der Wind ist ruhig, die Temperaturen sind kühl und das Wasser hat Zeit einzuziehen, bevor es verdunstet. Vermeiden Sie Abendbewässerung — das Gras bleibt über Nacht feucht, was das Krankheitsrisiko erhöht. Mittagsbewässerung verschwendet Wasser durch Verdunstung."},{"q":"Woher weiß ich, ob mein Rasen Wasser braucht?","a":"Gehen Sie auf den Rasen — wenn Ihre Fußabdrücke länger als ein paar Minuten sichtbar bleiben, braucht der Rasen Wasser. Grashalme, die sich längs falten oder einrollen oder eine blaugraue Farbe annehmen, sind ebenfalls Anzeichen für Trockenstress."},{"q":"Sollte ich die Bewässerung an die Jahreszeiten anpassen?","a":"Ja. In der Sommerhitze die Bewässerungshäufigkeit erhöhen. Im Frühjahr und Herbst reduzieren. Im Winter bei Kaltzeitrasengräsern nur bewässern, wenn 2–3 Wochen kein Niederschlag war. Warmzeitrasengräser brauchen in der Ruhephase kaum oder kein Wasser."}]},"soil_calculator":{"h1":"Erde-Rechner","meta_title":"Oberboden-Rechner — Wie Viel Erde Brauche Ich? (2026)","meta_description":"Berechnen Sie, wie viel Oberboden, Kompost oder Füllmaterial Sie für Ihren Rasen oder Garten brauchen. Ergebnisse in Kubikmetern, Kubikfuß und Säcken","area_label":"Fläche","area_help":"Geben Sie die zu bedeckende Fläche in Quadratmetern ein","depth_label":"Tiefe","depth_help":"Empfohlen: 10–15 cm für neue Rasen, 2,5–5 cm für Nachsaat","results_volume":"Benötigtes Volumen","results_cubic_yards":"Kubikyards","results_cubic_feet":"Kubikfuß","results_cubic_meters":"Kubikmeter","results_bags":"Sackäquivalente","bag_size":"{size} ft³ Sack","tip_depth":"10–15 cm Oberboden werden für neue Rasen empfohlen. 2,5–5 cm reichen für das Nachsaaten bestehender Rasen.","tip_compaction":"Bestellen Sie 10–15% extra für Setzung. Erde setzt sich nach dem Verteilen und Bewässern.","how_to_h2":"Wie Man Erdvolumen Berechnet","how_to_step1":"Messen Sie die Fläche, die Sie bedecken möchten, in Quadratmetern.","how_to_step2":"Entscheiden Sie, wie tief die Erde sein soll (in Zentimetern).","how_to_step3":"Multiplizieren Sie Fläche × Tiefe (in Metern), um Kubikmeter zu erhalten.","how_to_step4":"Multiplizieren Sie Kubikmeter mit 1,308, um in Kubikyards umzurechnen.","faq":[{"q":"Wie viel Oberboden brauche ich für einen neuen Rasen?","a":"Für einen neuen Rasen brauchen Sie 10–15 cm Oberboden. Für eine 100 m² große Fläche bei 10 cm Tiefe sind das etwa 10 Kubikmeter. Bestellen Sie 10–15% extra für Setzung."},{"q":"Wie viele Kubikyards hat ein Sack Erde?","a":"Ein Standard-Sack Oberboden enthält 1–2 Kubikfuß. Es gibt 27 Kubikfuß in 1 Kubikyard. Sie bräuchten also 14–27 Säcke für einen Kubikyard, je nach Sackgröße. Kauf in Schüttung ist für große Projekte meist günstiger."},{"q":"Was ist der Unterschied zwischen Oberboden und Gartenerde?","a":"Oberboden ist die oberste Schicht des natürlichen Bodens, geeignet für Nivellierung und Auffüllung. Gartenerde ist Oberboden gemischt mit Kompost und organischer Substanz, besser für Beete. Für neue Rasen verwenden Sie Oberboden; für Gärten Gartenerde."},{"q":"Wie tief sollte der Oberboden für Rollrasen sein?","a":"Sie brauchen mindestens 10 cm guten Oberboden vor der Rollrasenverlegung. 15 cm sind ideal für langfristige Wurzelgesundheit. Wenn Ihr vorhandener Boden schlecht ist, fügen Sie 5–10 cm Oberboden hinzu und arbeiten Sie ihn in den natürlichen Boden ein, bevor Sie Rollrasen verlegen."},{"q":"Sollte ich Kompost vor der Rollrasenverlegung hinzufügen?","a":"Ja, das Verteilen von 2,5–5 cm Kompost und Einarbeiten in die oberen 10–15 cm des Bodens verbessert Drainage, Nährstoffgehalt und Wurzeletablierung. Kompost ist besonders wichtig für tonige oder sandige Böden."}]},"area_converter":{"h1":"Flächenumrechner","meta_title":"Flächenumrechner — Quadratmeter, Hektar, Acres & Mehr (2026)","meta_description":"Rechnen Sie zwischen Quadratmetern, Quadratfuß, Acres, Hektar, Quadratyards und mehr um. Kostenloser Flächenumrechner mit Echtzeitergebnissen. Keine Anmeldung.","from_label":"Von","to_label":"Nach","value_label":"Wert","result_label":"Ergebnis","swap":"Tauschen","unit_sqin":"Quadratzoll","unit_sqft":"Quadratfuß","unit_sqyd":"Quadratyards","unit_sqm":"Quadratmeter","unit_ac":"Acres","unit_ha":"Hektar","unit_sqmi":"Quadratmeilen","conversion_formula":"{from_unit} nach {to_unit}","formula_text":"Umrechnungsformel","common_conversions_h2":"Häufige Umrechnungen","faq":[{"q":"Wie viele Quadratmeter hat ein Acre?","a":"Ein Acre entspricht 4.047 Quadratmetern bzw. 43.560 Quadratfuß. Das ist ungefähr ein Quadrat von 63,6 Metern Seitenlänge."},{"q":"Wie rechne ich Quadratfuß in Quadratmeter um?","a":"Multiplizieren Sie Quadratfuß mit 0,092903, um Quadratmeter zu erhalten. Zum Beispiel: 1.000 ft² × 0,092903 = 92,9 m². Für eine schnelle Schätzung teilen Sie Quadratfuß durch 10,764."},{"q":"Wie viele Acres hat mein Grundstück?","a":"Teilen Sie die Quadratfuß Ihres Grundstücks durch 43.560. Zum Beispiel: 10.890 ft² = 0,25 Acres (ein Viertelacre). 21.780 ft² = 0,5 Acres (ein halber Acre)."},{"q":"Was ist ein Hektar?","a":"Ein Hektar ist eine metrische Flächeneinheit, die 10.000 Quadratmetern oder etwa 2,471 Acres entspricht. Sie wird häufig in Ländern verwendet, die das metrische System für Landvermessung nutzen."},{"q":"Wie viele Quadratyards hat ein Quadratfuß?","a":"Ein Quadratyard entspricht 9 Quadratfuß. Um Quadratfuß in Quadratyards umzurechnen, teilen Sie durch 9. Zum Beispiel: 1.000 ft² ÷ 9 = 111,1 yd²."}],"unit_sqcm":"cm²","copy":"Kopieren","conversion_units":{"sqft":"Quadratfuß","sqm":"Quadratmeter","ac":"Acres","ha":"Hektar","sqyd":"Quadratyard","sqin":"Quadratzoll","sqmi":"Quadratmeilen","sqcm":"Quadratzentimeter"},"conversion_title_template":"{from} in {to} Umrechner","conversion_desc_template":"Rechnen Sie {from} in {to} um. Kostenloser Online-Flächenumrechner mit genauen Ergebnissen."},"lawn_care_calendar":{"h1":"Rasenpflegekalender","meta_title":"Rasenpflegekalender — Monat-für-Monat-Zeitplan (2026)","meta_description":"Monatlicher Rasenpflegeplan für Warm- und Kaltzeitrasengräser. Wissen, wann Sie düngen, mähen, bewässern und nachsäen sollen. Kostenloser Leitfaden.","season_toggle_label":"Rasensaison-Typ","phase_dormant":"Ruhephase","phase_pre_season":"Vorsaison","phase_active_growth":"Aktives Wachstum","phase_transition":"Übergang","phase_preparation":"Vorbereitung","priority_critical":"Kritisch","priority_recommended":"Empfohlen","priority_optional":"Optional","month_names":["Januar","Februar","März","April","Mai","Juni","Juli","August","September","Oktober","November","Dezember"],"warm_season":{"january":{"phase":"Ruhephase","tasks":["Vermeiden Sie das Betreten von gefrorenem oder bereiftem Gras","Rasenmäher warten — Klinge schärfen und Öl wechseln","Rasenpflegeziele und Budget für das Jahr planen"],"tip":"Gute Zeit, um Saatgut und Zubehör zu Nebensaisonpreisen zu bestellen."},"february":{"phase":"Ruhephase","tasks":["Vorauflaufherbizid Ende des Monats gegen Hirse ausbringen","Boden-pH und Nährstoffgehalt testen","Schutt und Blätter von der Rasenoberfläche entfernen"],"tip":"Das Timing des Vorauflaufherbizids ist kritisch — vor Erreichen von 13°C Bodentemperatur ausbringen."},"march":{"phase":"Vorsaison","tasks":["Vorauflaufherbizid ausbringen, falls im Februar nicht erfolgt","Vertikutieren und Filzablagerungen entfernen","Mit Mähen beginnen, wenn das Gras zu ergrünen beginnt"],"tip":"Nicht zu kurz mähen beim ersten Schnitt — nicht mehr als ⅓ der Halmlänge entfernen."},"april":{"phase":"Aktives Wachstum","tasks":["Erste Düngung ausbringen, wenn das Gras ergrünt","Regelmäßiges Mähen auf empfohlener Höhe für Ihre Rasensorte beginnen","Unkräuter punktuell mit Nachauflaufherbizid behandeln"],"tip":"Warten Sie, bis das Gras vollständig grün ist, bevor Sie düngen — zu frühes Düngen fördert Unkräuter."},"may":{"phase":"Aktives Wachstum","tasks":["Regelmäßiges Mähen fortsetzen — nie mehr als ⅓ der Halmlänge entfernen","Zweite Düngung ausbringen","Auf Engerlingsschäden achten und bei Bedarf behandeln"],"tip":"Mähhöhe mit steigenden Temperaturen leicht erhöhen, um Stress zu reduzieren."},"june":{"phase":"Aktives Wachstum","tasks":["Tief bewässern 1–2 mal pro Woche (25 mm insgesamt)","Auf Anzeichen von Chinch-Wanzen achten und sofort behandeln","Punktuelle Behandlungen bei hartnäckigen Unkräutern anwenden"],"tip":"Früh morgens bewässern, um Verdunstung und Krankheitsrisiko zu reduzieren."},"july":{"phase":"Aktives Wachstum","tasks":["Tiefes Bewässern während Trockenperioden fortsetzen","Mähhöhe erhöhen, um Hitzestress zu reduzieren","Düngen während der Höchsthitze vermeiden — Verbrennungsgefahr"],"tip":"Wenn das Gras durch Hitze/Trockenheit in Ruhephase geht, nicht versuchen, es mit Dünger zum Ergrünen zu zwingen."},"august":{"phase":"Übergang","tasks":["Auf Pilzkrankheiten bei feuchtem Wetter achten","Bewässerung nach Bedarf fortsetzen","Herbst-Nachsaat planen, falls gewünscht"],"tip":"Ende August ist die Zeit, Saatgut und Zubehör für Herbstprojekte zu bestellen."},"september":{"phase":"Übergang","tasks":["Herbstdünger ausbringen, um die Wurzeln vor der Ruhephase zu stärken","Lückige oder kahle Stellen nachsäen bei Bedarf","Mähfrequenz reduzieren, da das Wachstum sich verlangsamt"],"tip":"Die Herbsdüngung ist die wichtigste Anwendung des Jahres für Warmzeitrasengräser."},"october":{"phase":"Vorbereitung","tasks":["Winterdünger Mitte bis Ende des Monats ausbringen","Weiter mähen, bis das Gras aufhört zu wachsen","Laub rechen, um den Rasen nicht zu ersticken"],"tip":"Laub nicht länger als ein paar Tage auf dem Rasen liegen lassen — es blockiert das Sonnenlicht."},"november":{"phase":"Vorbereitung","tasks":["Letzter Schnitt der Saison — etwas kürzer als normal mähen","Gartengeräte reinigen und einlagern","Winter-Vorauflaufherbizid gegen Kaltzeitunkräuter ausbringen"],"tip":"Ein etwas kürzerer letzter Schnitt reduziert Verfilzung und Krankheitsrisiko über den Winter."},"december":{"phase":"Ruhephase","tasks":["Betreten von reifbedecktem Gras vermeiden","Restlichen Dünger und Chemikalien ordnungsgemäß lagern","Jahresrückblick und Verbesserungen für die nächste Saison planen"],"tip":"Der Winter ist eine gute Zeit, um Rasensorten zu recherchieren und für Frühjahrsprojekte zu planen."}},"cool_season":{"january":{"phase":"Ruhephase","tasks":["Betreten von gefrorenem Gras vermeiden, um Schäden zu verhindern","Rasenmäher warten — Klinge schärfen und Öl wechseln","Rasenpflegeziele für die kommende Saison planen"],"tip":"Gute Zeit, um Saatgut und Zubehör zu Winterpreisen zu bestellen."},"february":{"phase":"Vorsaison","tasks":["Boden-pH und Nährstoffgehalt testen","Vorauflaufherbizid Mitte bis Ende des Monats ausbringen","Schutt rechen und die Rasenoberfläche säubern"],"tip":"Das Timing des Vorauflaufherbizids ist kritisch — vor Erreichen von 13°C Bodentemperatur ausbringen."},"march":{"phase":"Vorsaison","tasks":["Vorauflaufherbizid ausbringen, falls im Februar nicht erfolgt","Leicht vertikutieren, um Winterschutt und Schneeschimmel zu entfernen","Mit Mähen beginnen, wenn das Gras über 8 cm hoch ist"],"tip":"Nicht überstürzt mit der Frühlingspflege beginnen — warten Sie, bis der Boden fest und trocken ist, um Verdichtung zu vermeiden."},"april":{"phase":"Aktives Wachstum","tasks":["Erste Düngung der Saison ausbringen","Regelmäßiges Mähen auf empfohlener Höhe beginnen","Lückige oder kahle Stellen nachsäen"],"tip":"Der Frühling ist die zweitbeste Zeit für Nachsaat — Herbst ist besser, aber Frühling funktioniert für kleine Reparaturen."},"may":{"phase":"Aktives Wachstum","tasks":["Regelmäßiges Mähen und Bewässern fortsetzen","Breitblattunkräuter punktuell behandeln","Auf Krankheiten bei feuchten Bedingungen achten"],"tip":"Rasenschnitt auf dem Rasen liegen lassen — er gibt Stickstoff an den Boden zurück (kostenloser Dünger)."},"june":{"phase":"Aktives Wachstum","tasks":["Mähhöhe für den Sommer erhöhen, um Hitzestress zu reduzieren","Tief und selten bewässern — 25–38 mm pro Woche","Auf Engerlingsschäden achten und bei Erreichen des Schwellenwerts behandeln"],"tip":"Höheres Gras beschattet den Boden, reduziert Verdunstung und unterdrückt Unkräuter."},"july":{"phase":"Übergang","tasks":["Tiefes Bewässern während heißer, trockener Perioden fortsetzen","Düngung während der Sommerhitze vermeiden","Auf Braunfleckigkeit und andere Pilzkrankheiten achten"],"tip":"Wenn das Gras bei extremer Hitze in Ruhephase geht, erholt es sich, wenn die Temperaturen sinken."},"august":{"phase":"Übergang","tasks":["Herbst-Nachsaat und Belüftung planen","Saatgut und Zubehör für Herbstprojekte bestellen","Bewässerung nach Bedarf fortsetzen"],"tip":"Ende August bis Anfang September ist die beste Zeit für die Nachsaat von Kaltzeitrasen."},"september":{"phase":"Aktives Wachstum","tasks":["Rasen belüften, um Verdichtung zu lösen","Lückige Stellen nachsäen — dies ist die beste Jahreszeit","Herbstdüngung ausbringen"],"tip":"Herbstnachsaat in Kombination mit Belüftung gibt dem Saatgut direkten Bodenkontakt für beste Keimung."},"october":{"phase":"Aktives Wachstum","tasks":["Wichtigste Düngung des Jahres ausbringen (Herbstdüngung)","Weiter mähen, solange das Gras wächst","Regelmäßig Laub rechen, um Ersticken zu vermeiden"],"tip":"Herbstdüngung baut Wurzelreserven für das Winterüberleben und das Frühjahrsergrünen auf."},"november":{"phase":"Vorbereitung","tasks":["Winterdünger Ende des Monats ausbringen","Letzter Schnitt der Saison — etwas kürzer mähen","Gartengeräte reinigen und winterfest machen"],"tip":"Die letzte Herbstdüngeranwendung ist die wichtigste des gesamten Jahres."},"december":{"phase":"Ruhephase","tasks":["Betreten von reif- oder schneebedecktem Gras vermeiden","Restlichen Dünger und Chemikalien ordnungsgemäß lagern","Rasenverbesserungen für das nächste Jahr planen"],"tip":"Der Winter ist ideal, um neue Rasensorten zu recherchieren und Frühjahrsprojekte zu planen."}},"faq":[{"q":"Wann sollte ich meinen Rasenpflegekalender beginnen?","a":"Beginnen Sie Ende Winter (Februar) mit der Überwachung Ihres Rasens. Die ersten aktiven Aufgaben beginnen typischerweise im Frühjahr, wenn die Bodentemperaturen 13°C erreichen. Kaltzeitrasengräser erwachen früher im Frühjahr; Warmzeitrasengräser starten später, wenn der Boden konstant warm ist."},{"q":"Wie oft sollte ich meinen Rasen düngen?","a":"Warmzeitrasengräser: 3–4 mal pro Jahr (Frühjahr bis Frühherbst). Kaltzeitrasengräser: 2–3 mal pro Jahr, mit der wichtigsten Anwendung im Herbst. Vermeiden Sie Düngung bei extremer Hitze oder wenn das Gras in Ruhephase ist."},{"q":"Wann ist die beste Zeit, meinen Rasen zu belüften?","a":"Belüften Sie Kaltzeitrasengräser im Frühherbst (September–Oktober). Belüften Sie Warmzeitrasengräser im Spätfrühling oder Frühsommer (Mai–Juni), wenn das Gras aktiv wächst und sich schnell erholen kann."},{"q":"Sollte ich Rasenschnitt auf dem Rasen liegen lassen?","a":"Ja, in den meisten Fällen. Rasenschnitt zersetzt sich schnell und gibt Stickstoff und organische Substanz an den Boden zurück. Dies kann den Düngebedarf um bis zu 25% reduzieren. Nur bei sehr langem, krankem Gras oder während der Unkrautsamenzeit Rasenschnitt entfernen."},{"q":"Wann sollte ich Vorauflaufherbizid ausbringen?","a":"Im Frühjahr ausbringen, bevor die Bodentemperaturen an 3+ aufeinanderfolgenden Tagen 13°C erreichen. Dies verhindert die Keimung von Hirse und anderen einjährigen Unkräutern. Eine zweite Anwendung 6–8 Wochen später sorgt für erweiterte Kontrolle."}]},"about":{"h1":"Über TurfCalculator","meta_title":"Über TurfCalculator — Kostenlose Rasenrechner Für Alle","meta_description":"Erfahren Sie mehr über TurfCalculator — kostenlose, präzise Rasen- und Rollrasenrechner für Hausbesitzer","mission_h2":"Unsere Mission","mission_p1":"TurfCalculator bietet kostenlose, präzise und schnelle Rasenrechner für Hausbesitzer und Heimwerker. Ob Sie Rollrasen kaufen, Saatgut säen oder Ihren Rasenpflegeplan erstellen — wir liefern Ihnen die Zahlen in 30 Sekunden oder weniger.","mission_p2":"Keine Anmeldung. Keine E-Mail. Keine Datenerfassung. Einfach Werkzeuge, die funktionieren.","how_we_calculate_h2":"Wie Wir Rechnen","how_we_calculate_p1":"Alle unsere Rechner verwenden branchenübliche Formeln und Daten von Universitätserweiterungsdiensten, USDA-Richtlinien und Rasenforschungsinstituten. Wir nennen unsere Quellen und halten unsere Daten aktuell.","how_we_calculate_p2":"Alle Berechnungen erfolgen in Ihrem Browser — wir sehen nie Ihre Eingaben oder Ergebnisse. Ihre Daten bleiben auf Ihrem Gerät.","who_for_h2":"Für Wen Ist Das?","who_for_p1":"Hausbesitzer, die eine Rollrasenverlegung oder Rasenrenovierung planen.","who_for_p2":"Heimwerker-Gärtner, die wissen möchten, wie viel Saatgut, Dünger oder Erde sie kaufen sollen.","who_for_p3":"Jeden, der im Gartencenter-Gang steht und sich fragt: \"Wie viel brauche ich?\"","disclaimer_h2":"Haftungsausschluss","disclaimer_p":"Unsere Rechner liefern Schätzungen basierend auf Branchendurchschnitten. Tatsächliche Mengen können je nach Ihren spezifischen Standortbedingungen, den Spezifikationen Ihres lokalen Anbieters und den Verlegungsmethoden abweichen. Überprüfen Sie Mengen immer bei Ihrem lokalen Anbieter vor dem Kauf."},"privacy_policy":{"h1":"Datenschutzerklärung","meta_title":"Datenschutzerklärung — TurfCalculator","meta_description":"Datenschutzerklärung von TurfCalculator. Wir erheben keine personenbezogenen Daten. Alle Berechnungen erfolgen in Ihrem Browser","last_updated":"Letzte Aktualisierung: Mai 2026","intro_p":"TurfCalculator respektiert Ihre Privatsphäre. Diese Richtlinie erklärt, welche Daten wir erheben, wie wir sie verwenden und welche Rechte Sie haben.","data_collection_h2":"Daten, Die Wir Erheben","data_collection_p1":"Wir erheben keine personenbezogenen Daten. Wir fordern keine Konten, E-Mails, Namen oder sonstige personenbezogene Informationen.","data_collection_p2":"Alle Rechnereingaben und -ergebnisse werden vollständig in Ihrem Browser verarbeitet. Wir sehen, speichern oder übermitteln Ihre Berechnungen nie.","analytics_h2":"Analyse","analytics_p1":"Wir können Google Analytics 4 verwenden, um zu verstehen, wie Besucher unsere Seite nutzen. GA4 verwendet anonymisierte IP-Adressen und erhebt keine personenbezogenen Informationen.","analytics_p2":"Analysen werden erst aktiviert, nachdem Sie über unser Cookie-Banner Ihre Zustimmung erteilt haben.","cookies_h2":"Cookies","cookies_p1":"Essenzielle Cookies: Die Spracheinstellung wird im localStorage Ihres Browsers gespeichert (kein Cookie). Dies ist für die Funktionalität der Seite erforderlich.","cookies_p2":"Analyse-Cookies: Werden von Google Analytics erst nach Ihrer Zustimmung gesetzt. Dazu gehören die _ga- und _gid-Cookies.","cookies_p3":"Werbe-Cookies: Können in Zukunft von Google AdSense gesetzt werden, nur nach Ihrer Zustimmung.","third_party_h2":"Drittanbieter-Dienste","third_party_p1":"Cloudflare: Unser Hosting- und CDN-Anbieter. Cloudflare kann technische Daten für Sicherheit und Leistung erheben.","third_party_p2":"Google Analytics: Siehe den Abschnitt Analyse oben.","third_party_p3":"Google AdSense: Kann in Zukunft Werbung anzeigen. Siehe den Abschnitt Cookies oben.","gdpr_h2":"DSGVO-Konformität","gdpr_p1":"Da wir keine personenbezogenen Daten erheben, gelten die meisten DSGVO-Pflichten nicht für unseren Kernservice.","gdpr_p2":"Sie haben das Recht, Analyse- und Werbe-Cookies über unser Cookie-Zustimmungsbanner abzulehnen.","gdpr_p3":"Bei Fragen zu Ihren Daten kontaktieren Sie uns unter der unten angegebenen E-Mail-Adresse.","ccpa_h2":"CCPA-Konformität","ccpa_p1":"Wir verkaufen keine personenbezogenen Informationen. Wir teilen keine personenbezogenen Informationen mit Dritten über Analyse- und Werbedienste hinaus.","ccpa_p2":"Es werden keine personenbezogenen Informationen durch unsere Kern-Rechnerdienste erhoben.","contact_h2":"Kontakt","contact_p":"Bei datenschutzbezogenen Anfragen kontaktieren Sie uns bitte über die Informationen auf unserer Über-uns-Seite."},"terms":{"h1":"Nutzungsbedingungen","meta_title":"Nutzungsbedingungen — TurfCalculator","meta_description":"Nutzungsbedingungen für TurfCalculator. Kostenlose Rasen- und Rollrasenrechner werden wie besehen zu Informationszwecken bereitgestellt.","last_updated":"Letzte Aktualisierung: Mai 2026","acceptance_h2":"Annahme Der Bedingungen","acceptance_p":"Mit der Nutzung von TurfCalculator akzeptieren Sie diese Nutzungsbedingungen. Wenn Sie nicht einverstanden sind, nutzen Sie die Seite bitte nicht.","use_h2":"Nutzung Des Dienstes","use_p1":"TurfCalculator bietet kostenlose Online-Rechner zur Schätzung von Rasen- und Rollrasenmaterialmengen. Alle Ergebnisse sind Schätzungen und dienen nur zu Informationszwecken.","use_p2":"Sie dürfen die Rechner für persönliche, nicht-kommerzielle Zwecke nutzen. Sie dürfen Inhalte oder Werkzeuge nicht ohne Genehmigung extrahieren, kopieren oder weiterverbreiten.","accuracy_h2":"Genauigkeitshinweis","accuracy_p1":"Rechnerergebnisse basieren auf branchenüblichen Formeln und Durchschnittsdaten. Der tatsächliche Materialbedarf kann je nach Standortbedingungen, Anbieter-Spezifikationen, Verlegungsmethoden und regionalen Faktoren abweichen.","accuracy_p2":"Überprüfen Sie Mengen immer bei Ihrem lokalen Anbieter vor dem Kauf. TurfCalculator ist nicht verantwortlich für Über- oder Unterkauf als Ergebnis dieser Berechnungen.","no_liability_h2":"Haftungsbeschränkung","no_liability_p":"TurfCalculator wird wie besehen ohne jegliche Gewährleistung bereitgestellt. Wir haften nicht für Schäden aus der Nutzung unserer Rechner, einschließlich, aber nicht beschränkt auf finanzielle Verluste durch falsche Materialschätzungen.","intellectual_property_h2":"Geistiges Eigentum","intellectual_property_p":"Alle Inhalte, Designs und Codes auf TurfCalculator sind Eigentum von TurfCalculator. Sie dürfen unsere Werkzeuge oder Inhalte nicht ohne schriftliche Genehmigung kopieren, ändern oder verbreiten.","changes_h2":"Änderungen Der Bedingungen","changes_p":"Wir können diese Bedingungen von Zeit zu Zeit aktualisieren. Fortgesetzte Nutzung der Seite nach Änderungen gilt als Akzeptanz der aktualisierten Bedingungen."},"disclaimer":{"h1":"Haftungsausschluss","meta_title":"Haftungsausschluss — TurfCalculator","meta_description":"Haftungsausschluss von TurfCalculator. Rechnerergebnisse sind Schätzungen. Überprüfen Sie immer bei Ihrem lokalen Anbieter vor dem Materialkauf.","last_updated":"Letzte Aktualisierung: Mai 2026","main_p1":"Dieser Rechner liefert Schätzungen basierend auf branchenüblichen Formeln und Daten. Der tatsächliche Bedarf an Rollrasen, Saatgut und Materialien kann je nach Standortbedingungen, Anbieter-Spezifikationen und Verlegungsmethoden abweichen.","main_p2":"Überprüfen Sie Mengen immer bei Ihrem lokalen Anbieter vor dem Kauf. TurfCalculator ist nicht verantwortlich für Über- oder Unterkauf als Ergebnis dieser Berechnungen.","prices_h2":"Preisschätzungen","prices_p":"Preisschätzungen sind nur Spannen, keine Angebote. Tatsächliche Preise variieren nach Region, Anbieter, Rasensorte, Menge und Saison. Kontaktieren Sie lokale Anbieter für aktuelle Preise.","recommendations_h2":"Rasensorten-Empfehlungen","recommendations_p":"Rasensorten-Informationen sind allgemeine Hinweise basierend auf typischen Bedingungen, keine professionelle Beratung. Lokales Klima, Bodenverhältnisse und Mikroklima können die Rasenleistung beeinflussen. Konsultieren Sie einen lokalen Rasenpflegeprofi für spezifische Empfehlungen.","calendar_h2":"Rasenpflegekalender","calendar_p":"Der Rasenpflegekalender basiert auf typischen Bedingungen und allgemeinen Richtlinien. Das tatsächliche Timing kann je nach Ihrem lokalen Klima, Wetterverhältnissen und spezifischen Rasenbedingungen abweichen. Passen Sie das Timing nach den Empfehlungen Ihres lokalen Beratungsdienstes an.","professional_h2":"Professionelle Beratung","professional_p":"Ergebnisse unserer Rechner sollten nicht die Beratung durch einen qualifizierten Rasenpflegeprofi ersetzen. Für komplexe Projekte, Bodenuntersuchungen oder Schädlingsprobleme konsultieren Sie einen lokalen Experten."},"cookie_policy":{"h1":"Cookie-Richtlinie","meta_title":"Cookie-Richtlinie — TurfCalculator","meta_description":"Cookie-Richtlinie von TurfCalculator. Erfahren Sie, welche Cookies wir verwenden, warum wir sie verwenden und wie Sie Ihre Einstellungen verwalten.","last_updated":"Letzte Aktualisierung: Mai 2026","what_are_h2":"Was Sind Cookies?","what_are_p":"Cookies sind kleine Textdateien, die auf Ihrem Gerät gespeichert werden, wenn Sie eine Website besuchen. Sie helfen der Seite, Ihre Einstellungen zu speichern und Ihr Erlebnis zu verbessern.","essential_h2":"Essenzielle Cookies","essential_p1":"Diese sind für das ordnungsgemäße Funktionieren der Seite erforderlich.","essential_p2":"Spracheinstellung: Im localStorage gespeichert (kein traditionelles Cookie). Speichert Ihre Sprachwahl zwischen Besuchen.","essential_p3":"Cookie-Einwilligung: Speichert Ihre Cookie-Präferenz, damit wir Sie nicht bei jedem Besuch erneut fragen.","analytics_h2":"Analyse-Cookies","analytics_p1":"Diese helfen uns zu verstehen, wie Besucher unsere Seite nutzen, damit wir sie verbessern können.","analytics_cookie_ga":"_ga: Unterscheidet eindeutige Besucher. Läuft nach 2 Jahren ab.","analytics_cookie_gid":"_gid: Unterscheidet eindeutige Besucher pro Tag. Läuft nach 24 Stunden ab.","analytics_p2":"Analyse-Cookies werden erst nach Ihrer Zustimmung über das Cookie-Banner gesetzt.","advertising_h2":"Werbe-Cookies","advertising_p1":"In Zukunft kann Google AdSense Cookies setzen, um personalisierte Werbung anzuzeigen.","advertising_p2":"Werbe-Cookies werden erst nach Ihrer Zustimmung gesetzt.","advertising_p3":"Sie können personalisierte Werbung über die Google-Anzeigeneinstellungen deaktivieren.","managing_h2":"Verwaltung Ihrer Cookie-Einstellungen","managing_p1":"Sie können Ihre Cookie-Einstellungen jederzeit über das Cookie-Banner oder den Einstellungslink in der Fußzeile ändern.","managing_p2":"Sie können Cookies auch über Ihre Browsereinstellungen steuern. Beachten Sie, dass die Deaktivierung aller Cookies die Funktionalität der Seite beeinträchtigen kann.","managing_p3":"Weitere Informationen zum Online-Tracking und Ihren Rechten finden Sie auf der Website Ihrer lokalen Datenschutzbehörde."},"sod_calc":{"total_area_label":"Gesamtfläche","area_with_waste":"Fläche mit {waste}% Verschnitt","rolls_needed_roll":"Benötigte Rollen ({roll})","roll_standard_short":"Standardrolle","roll_mini_short":"Mini-Rolle","roll_large_short":"Große Rolle","price_per_sqft":"Preis pro sq ft","cost_help":"Geben Sie Ihren lokalen Preis pro Quadratfuß ein, um die Gesamtkosten zu schätzen."},"fert_calc":{"bags_15lb":"15-lb-Säcke","bags_30lb":"30-lb-Säcke"},"seed_calc":{"bags_5lb":"5-lb-Säcke","bags_20lb":"20-lb-Säcke"},"soil_calc":{"bags_2cuft":"2-ft³-Säcke","bags_075cuft":"0,75-ft³-Säcke","bags_40lb":"40-lb-Säcke","liters":"Liter","bags_1cuft":"1 cu ft Säcke","bags_15cuft":"1.5 cu ft Säcke","results_cubic_yards":"Kubikyard"},"area_calc":{"square_feet":"Quadratfuß","square_meters":"Quadratmeter","send_to_sod":"Zum Rasenrechner senden →","subtract":"Abziehen","add_area":"Bereich","shape_rectangle":"Rechteck","shape_circle":"Kreis","shape_triangle":"Dreieck","length_ft":"Länge (ft)","width_ft":"Breite (ft)","radius_ft":"Radius (ft)","base_ft":"Basis (ft)","height_ft":"Höhe (ft)","square_yards":"Quadratyard","acres":"Acre"},"lang_name":"Deutsch"};